/****
* Validate that at least one of the numeric exposure fields
* (CQP_MLI_USD, CQP_MLE_USD, CQP_MLD_USD) is not null or 0
* inside CQP_TRANSIT_EXPOSURE array.
* Returns: { isValid: Boolean, message: String }
* By Adriana Centellas
* Edited By Natalia Mendez
****/

const exposures = this.CQP_TRANSIT_EXPOSURE || [];

// If array is empty
if (exposures.length === 0) {
  return {
    isValid: false,
    message: "Transit Exposure data is missing."
  };
}

// Check if at least one item has any value different from 0/null
const hasValidExposure = exposures.some(item => {
  const mli = parseFloat(item.CQP_MLI_USD) || 0;
  const mle = parseFloat(item.CQP_MLE_USD) || 0;
  const mld = parseFloat(item.CQP_MLD_USD) || 0;

  return mli !== 0 || mle !== 0 || mld !== 0;
});
//If user wants to go back on the process the required values are now non required
if (this.CQP_SUBMIT != "BACK") {
  // Return structured response
  if (hasValidExposure) {
    return {
      isValid: true,
      message: ""
    };
  } else {
    return {
      isValid: false,
      message: "At least one exposure value must be completed."
    };
  }
} else {
  return {
    isValid: true,
    message: ""
  };
}

/****
 * Validate that at least one of the numeric fields
 * (CQP_TOTAL_IMPORTS_ANNUAL_USD, CQP_TOTAL_EXPORTS_ANNUAL_USD, CQP_TOTAL_DOMESTIC_ANNUAL_USD)
 * in the CQP_TRANSIT array is different from null or 0.
 * Returns: { isValid: Boolean, message: String }
 * By Adriana Centellas
 * Edited By Natalia Mendez
 ****/

const transitArray = this.CQP_TRANSIT || [];

// Check if the array exists and has elements
if (transitArray.length === 0) {
  return {
    isValid: false,
    message: "Transit data is missing."
  };
}

// Verify that at least one record has a valid numeric value
const hasValidTransit = transitArray.some(item => {
  const imports = parseFloat(item.CQP_TOTAL_IMPORTS_ANNUAL_USD) || 0;
  const exportsVal = parseFloat(item.CQP_TOTAL_EXPORTS_ANNUAL_USD) || 0;
  const domestic = parseFloat(item.CQP_TOTAL_DOMESTIC_ANNUAL_USD) || 0;

  // Return true if any of them is not 0
  return imports !== 0 || exportsVal !== 0 || domestic !== 0;
});

//If user wants to go back on the process the required values are now non required
if (this.CQP_SUBMIT != "BACK") {
  // Return structured response
  if (hasValidTransit) {
    return {
      isValid: true,
      message: ""
    };
  } else {
    return {
      isValid: false,
      message: "At least one of the following fields must have a value different from 0 or null: Imports, Exports, or Domestic Annual USD."
    };
  }
} else {
  return {
    isValid: true,
    message: ""
  };
}

/*
* Validate if CQP_STORAGE_EXPOSURE array has any non-zero numeric value
*
* @param (Array) storageExposure // Array of objects with storage exposure data
* @return (Boolean) true if there is any non-zero numeric value, false otherwise
*
* by Adriana Centellas
*/

  const storageExposure = this.CQP_STORAGE_EXPOSURE;

  // Check if array exists and has at least one element
  if (!Array.isArray(storageExposure) || storageExposure.length === 0) {
    return false;
  }

  // Take the first (and usually only) object in the array
  const data = storageExposure[0];

  // List of keys to validate
  const numericKeys = [
    "CQP_STORAGE_EEL",
    "CQP_HISTORICAL_EEL",
    "CQP_STORAGE_AGG",
    "CQP_HISTORICAL_AGG",
    "CQP_TOTAL_FORTE_USD_EEL",
    "CQP_TOTAL_FORTE_USD_AGG"
  ];

  // Check if any numeric field is greater than 0
  for (const key of numericKeys) {
    const value = parseFloat(data[key]) || 0;
    if (value > 0) {
      return true; // At least one field has a non-zero value
    }
  }

  return false; // All values are zero or null

/*******
 * Enable/disable dropdown when inception date not selected
 * This calc only controls UI behavior (disabled state of fields)
 *
 * By Adriana Centellas
 *******/

// List of selectors for the dropdowns you want to toggle
var selectorsToToggle = [
  'CQP_PERIODS_DISABLED'
];

// Condition: disable when inception date is null
var disableDropdown = (this.CQP_INCEPTION_DATE == null);

setTimeout(function () {
  selectorsToToggle.forEach(function (selectorName) {

    // For dropdowns → use SELECT instead of INPUT
    var $dropdown = $('[selector="' + selectorName + '"] select');

    if (!$dropdown.length) {
      return; // Field not found
    }

    // Clean previous styles
    $dropdown.removeClass('inputDisabled');

    if (disableDropdown) {
      // Disable dropdown
      $dropdown.prop('disabled', true);
      $dropdown.addClass('inputDisabled');
    } else {
      // Re-enable dropdown
      $dropdown.prop('disabled', false);
    }

  });
}, 300);

// UI-only calc → return nothing
return null;

/*****
 * CQP_STORAGE_JUMP
 * Visibility Rule
 * By Adriana Centellas
 */

let ret = true;

if (this.CQP_STORAGE_FILLED) {
    ret = this.CQP_STORAGE[0].CQP_STORAGE_CHECKBOXES_VALIDATION.valid;
}

return this.CQP_STORAGE[0].CQP_STORAGE_VALIDATION.valid && ret;

/******
 * Color handler for CQP_TOTAL_CLAIMS_COMBINED_VARIATION.
 * This script DOES NOT calculate the variation.
 * It only reads the existing value and applies colors repeatedly.
 *
 * By Adriana Centellas
 */

// Avoid duplicate interval registration
if (!window.cqpVariationColorInterval) {

  window.cqpVariationColorInterval = setInterval(function () {

    $('[selector="CQP_TOTAL_CLAIMS_COMBINED_VARIATION"] input').each(function () {

      var input = $(this);
      var rawValue = input.val();

      if (rawValue === null || rawValue === undefined || rawValue === '') {
        rawValue = 0;
      }

      rawValue = String(rawValue)
        .replace(/\./g, '')   // Remove thousand separator
        .replace(',', '.')    // Convert decimal comma
        .replace('%', '')
        .trim();

      var value = parseFloat(rawValue);

      if (isNaN(value)) {
        value = 0;
      }

      input.removeClass('inputError inputOk');

      if (value < 0) {
        input.addClass('inputError');
      } else if (value > 0) {
        input.addClass('inputOk');
      }

    });

  }, 400);
}

// Bind change listeners once
if (!window.cqpVariationColorEventsBound) {

  window.cqpVariationColorEventsBound = true;

  $(document).on(
    'input change blur',
    '[selector="CQP_TOTAL_CLAIMS_COMBINED_VARIATION"] input',
    function () {

      $('[selector="CQP_TOTAL_CLAIMS_COMBINED_VARIATION"] input').each(function () {

        var input = $(this);
        var rawValue = input.val();

        if (rawValue === null || rawValue === undefined || rawValue === '') {
          rawValue = 0;
        }

        rawValue = String(rawValue)
          .replace(/\./g, '')
          .replace(',', '.')
          .replace('%', '')
          .trim();

        var value = parseFloat(rawValue);

        if (isNaN(value)) {
          value = 0;
        }

        input.removeClass('inputError inputOk');

        if (value < 0) {
          input.addClass('inputError');
        } else if (value > 0) {
          input.addClass('inputOk');
        }

      });

    }
  );
}

return 0;

/*
* Calc Show request error dialog
* by Helen Callisaya
* Modified by Mateo Rada
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERROR.data.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == null || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

